import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.ValidationException;

import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userInput = br.readLine();

        try {
            // Validate and sanitize user input to prevent XSS attacks
            String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);

            System.out.println("Hello, " + sanitizedInput + "! Welcome to our website!");
        } catch (ValidationException e) {
            System.err.println("Error validating user input");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
